SELECT progress_id, AVG(evaluation_score) AS average_score
FROM rotation_evaluations
GROUP BY progress_id;

SELECT AVG(evaluation_score) AS average_score, COUNT(evaluation_id) AS number_of_evaluations
FROM rotation_evaluations
WHERE progress_id = 1;

SELECT rotation_name
FROM resident_progress
WHERE completed = 1;

SELECT name, medical_school, graduation_date, license_state
FROM residents
WHERE resident_id = 0;

SELECT COUNT(resident_id) AS number_of_graduates
FROM residents
WHERE medical_school = 'Harvard Medical School';

SELECT evaluation_id, progress_id, evaluator_id, evaluation_date, evaluation_score, evaluation_comments
FROM rotation_evaluations
WHERE evaluation_score >= 4.0;
